const item = $input.item.json;

// The Gemini node's text output can land under different keys depending on
// version/config - grab whichever is present.
let raw = item.content || item.text || item.output || item.message?.content || '';

// If raw is an object, try to extract the text
if (typeof raw === 'object' && raw !== null) {
  if (raw.parts && Array.isArray(raw.parts) && raw.parts.length > 0) {
    raw = raw.parts[0].text || raw.parts[0] || '';
  } else if (raw.text) {
    raw = raw.text;
  } else {
    raw = JSON.stringify(raw);
  }
}

if (typeof raw !== 'string') {
  raw = String(raw);
}

function extract(label, str) {
  const escapedLabel = label.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const regex = new RegExp(`### ${escapedLabel}:([\\s\\S]*?)(?=\\n### |$)`, 'i');
  const match = str.match(regex);
  return match ? match[1].trim() : '';
}

function extractScore(label, str) {
  const regex = new RegExp(`${label}:\\s*(\\d+)/\\d+`, 'i');
  const match = str.match(regex);
  return match ? match[1] : '0';
}

function extractBreakdown(str) {
  const regex = /### BREAKDOWN:([\s\S]*?)(?=\n### |$)/i;
  const match = str.match(regex);
  return match ? match[1].trim() : '';
}

// Format text with proper line breaks for Google Sheets
function formatForSheets(text) {
  if (!text) return '';
  // Replace \n with actual line breaks for Google Sheets
  return text.replace(/\\n/g, '\n').replace(/\n/g, ' ');
}

// Format bullet points with dashes and proper spacing
function formatBulletPoints(text) {
  if (!text) return '';
  // Split by lines, trim, and join with semicolons for Google Sheets
  return text.split('\n')
    .map(line => line.trim())
    .filter(line => line.length > 0)
    .join('; ');
}

function formatStrengths(text) {
  if (!text) return '';
  // Extract bullet points and format
  return text.split('\n')
    .map(line => line.trim())
    .filter(line => line.startsWith('-') || line.startsWith('•'))
    .map(line => line.replace(/^[-•]\s*/, ''))
    .join('; ');
}

function formatGaps(text) {
  if (!text) return '';
  return text.split('\n')
    .map(line => line.trim())
    .filter(line => line.startsWith('-') || line.startsWith('•'))
    .map(line => line.replace(/^[-•]\s*/, ''))
    .join('; ');
}

// Extract individual scores from breakdown
function extractBreakdownScores(str) {
  const scores = {
    technical: extractScore('Technical Skills', str),
    experience: extractScore('Experience', str),
    education: extractScore('Education', str),
    projects: extractScore('Projects', str),
    formatting: extractScore('Formatting', str),
    softSkills: extractScore('Soft Skills', str)
  };
  return scores;
}

const breakdownText = extractBreakdown(raw);
const scores = extractBreakdownScores(breakdownText);

// Extract strengths and gaps with proper formatting
let strengths = extract('STRENGTHS', raw);
let gaps = extract('GAPS', raw);

// Format strengths as semicolon-separated list
strengths = strengths.split('\n')
  .map(line => line.trim())
  .filter(line => line.startsWith('-') || line.startsWith('•'))
  .map(line => line.replace(/^[-•]\s*/, ''))
  .join('; ');

// Format gaps as semicolon-separated list
gaps = gaps.split('\n')
  .map(line => line.trim())
  .filter(line => line.startsWith('-') || line.startsWith('•'))
  .map(line => line.replace(/^[-•]\s*/, ''))
  .join('; ');

// Format interview questions as semicolon-separated list
let interviewQuestions = extract('INTERVIEW_QUESTIONS', raw);
interviewQuestions = interviewQuestions.split('\n')
  .map(line => line.trim())
  .filter(line => line.length > 0 && line.match(/^\d+\./))
  .join('; ');

return {
  json: {
    // Basic info
    CandidateName: extract('CANDIDATE_NAME', raw),
    ContactInfo: extract('CONTACT_INFO', raw),

    // Scores
    TotalScore: extract('TOTAL_SCORE', raw),
    TechnicalScore: scores.technical,
    ExperienceScore: scores.experience,
    EducationScore: scores.education,
    ProjectsScore: scores.projects,
    FormattingScore: scores.formatting,
    SoftSkillsScore: scores.softSkills,
    KeywordMatches: extract('KEYWORD_MATCHES \\(1-10\\)', raw),

    // Formatted sections
    Strengths: strengths,
    Gaps: gaps,
    Recommendation: extract('RECOMMENDATION', raw),
    InterviewQuestions: interviewQuestions,
    Notes: extract('NOTES', raw),

    // Metadata
    ProcessedAt: new Date().toISOString(),

    // Raw response (for debugging)
    RawResponse: raw
  }
};
